import fs from 'node:fs';
import path from 'node:path';
export class JsonlRecorder{ constructor({dir='data/captures',sessionId=`lce-session-${Date.now()}`}={}){ this.dir=dir; this.sessionId=sessionId; this.sessionDir=path.join(dir,sessionId); this.file=path.join(this.sessionDir,'snapshots.jsonl'); this.rows=0; this.active=false; } start(meta={}){ fs.mkdirSync(this.sessionDir,{recursive:true}); fs.writeFileSync(path.join(this.sessionDir,'session.json'),JSON.stringify({sessionId:this.sessionId,startedAt:new Date().toISOString(),marketDataOnly:true,...meta},null,2)); this.active=true; return this.status(); } write(snapshot){ if(!this.active) return this.status(); fs.appendFileSync(this.file,JSON.stringify({time:new Date().toISOString(),snapshot})+'\n'); this.rows++; return this.status(); } stop(){ this.active=false; return this.status(); } status(){ return {active:this.active,sessionId:this.sessionId,rows:this.rows,file:this.file}; } }
export function readJsonl(file){ if(!fs.existsSync(file)) return []; return fs.readFileSync(file,'utf8').split(/\r?\n/).filter(Boolean).map(x=>JSON.parse(x)); }
export class ReplayReader{ constructor({file}){ this.frames=readJsonl(file); this.index=0; } next(){ if(this.index>=this.frames.length) return {done:true,value:null}; return {done:false,value:this.frames[this.index++],index:this.index-1}; } reset(){ this.index=0; } }
